('ONET-SLAUGHTERERS_AND_MEAT_PACKERS', 'source_onet_slaughterers_and_meat_packers', 'Slaughterers and Meat Packers', 'Slaughterers and Meat Packers is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'Perform nonroutine or precision functions involving the preparation of large portions of meat. Work may include specialized slaughtering tasks, cutting standard or premium cuts of meat for marketing, making sausage, or wrapping meats. Work typically occurs in slaughtering, meat packing, or wholesale establishments.', ARRAY['Animal Killer','Animal Sticker','Animal Stunner','Beef Killer','Beef Splitter','Bitter','Boning Room Worker','Brainer','Butcher','Cattle Killer','Cold Storage Worker','Deboner','Halal Meat Packer','Hog Killer','Hog Slaughterer','Hog Sticker','Live Hanger','Livestock Slaughterer','Meat Associate','Meat Clerk','Meat Department Associate','Meat Dresser','Meat Market Associate','Meat Packager','Meat Packer','Meat Processor','Meat Wrapper','Pelt Dropper','Pig Sticker','Poleman','Poultry Processor','Poultry Slaughterer','Religious Ritual Slaughterer','Saw Man','Saw Operator','Sawyer','Scriber','Seafood Processor','Shactor','Sheep Killer','Shochet','Side Puller','Slaughterer','Tank House Operator','Throat Cutter','Wrap Around Facilitator','Wrapper']::text[], ARRAY['Slaughterers and Meat Packers','Animal Killer','Animal Sticker','Animal Stunner','Beef Killer','Beef Splitter','Bitter','Boning Room Worker','Brainer','Butcher','Cattle Killer','Cold Storage Worker','Deboner','Halal Meat Packer','Hog Killer','Hog Slaughterer','Hog Sticker','Live Hanger','Livestock Slaughterer','Meat Associate','Meat Clerk','Meat Department Associate','Meat Dresser','Meat Market Associate','Meat Packager','Meat Packer']::text[], ARRAY['Reading Comprehension','Active Listening','Writing','Speaking','Mathematics','Science','Critical Thinking','Active Learning','Learning Strategies','Monitoring','Social Perceptiven